--
-- Table structure for table `invoices`
--

DROP TABLE IF EXISTS `invoices`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `invoices` (
  `id` int NOT NULL AUTO_INCREMENT,
  `table_id` int DEFAULT NULL,
  `cashier_id` int DEFAULT NULL,
  `order_type` enum('table','takeaway') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'table',
  `floor_id` int DEFAULT NULL,
  `status` enum('open','paid','void') COLLATE utf8mb4_unicode_ci DEFAULT 'open',
  `subtotal_usd` decimal(12,2) NOT NULL DEFAULT '0.00',
  `subtotal_khr` int NOT NULL DEFAULT '0',
  `discount_pct` decimal(8,6) NOT NULL DEFAULT '0.000000',
  `discount_amount_usd` decimal(10,2) NOT NULL DEFAULT '0.00',
  `discount_amount_khr` int NOT NULL DEFAULT '0',
  `discount_usd` decimal(12,2) NOT NULL DEFAULT '0.00',
  `discount_khr` int NOT NULL DEFAULT '0',
  `total_usd` decimal(12,2) NOT NULL DEFAULT '0.00',
  `total_khr` int NOT NULL DEFAULT '0',
  `pay_currency` enum('USD','KHR') COLLATE utf8mb4_unicode_ci DEFAULT 'USD',
  `pay_method` enum('cash','qr') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'cash',
  `qr_ref` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cash_in_usd` decimal(12,2) DEFAULT '0.00',
  `cash_in_khr` int DEFAULT '0',
  `change_usd` decimal(12,2) DEFAULT '0.00',
  `change_khr` int DEFAULT '0',
  `usd_to_khr` int NOT NULL,
  `paid_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `whole_discount_usd` decimal(10,2) NOT NULL DEFAULT '0.00',
  `whole_discount_khr` int NOT NULL DEFAULT '0',
  `use_manual_discount` tinyint(1) NOT NULL DEFAULT '0',
  `manual_discount_khr` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `floor_id` (`floor_id`),
  KEY `idx_invoices_paid_at` (`paid_at`),
  KEY `invoices_ibfk_1` (`table_id`),
  CONSTRAINT `invoices_ibfk_1` FOREIGN KEY (`table_id`) REFERENCES `tables` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `invoices_ibfk_2` FOREIGN KEY (`floor_id`) REFERENCES `floors` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=346 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

